# tests/unit/test_validators.py import pytest from apps.users.validators import validate_password, PasswordValidationResult
class TestPasswordValidator: """Tests for password validation."""
@pytest.mark.parametrize("password,is_valid", [ ("ValidPass123!", True), ("Another$ecure1", True), ("short1!", False), # Too short ("nouppercase123!", False), # No uppercase ("NOLOWERCASE123!", False), # No lowercase ("NoDigitsHere!!", False), # No digits ("NoSpecial123abc", False), # No special char ]) def test_password_validation(self, password, is_valid): """Password validation with various inputs.""" result = validate_password(password) assert result.is_valid == is_valid
@pytest.mark.parametrize("password,expected_errors", [ ("short", ["too_short", "no_uppercase", "no_digit", "no_special"]), ("NoDigits!!", ["no_digit"]), ("nouppercaseorspecial1", ["no_uppercase", "no_special"]), ]) def test_error_codes(self, password, expected_errors): """Validation returns correct error codes.""" result = validate_password(password) assert set(result.error_codes) == set(expected_errors)

import pytest
from rest_framework import status


@pytest.mark.django_db
class TestUserCreateAPI:
    """Tests for POST /api/v1/users/."""

    endpoint = "/api/v1/users/"

    @pytest.mark.parametrize("field,value,error", [
        ("email", "invalid", "Enter a valid email address"),
        ("email", "", "This field may not be blank"),
        ("name", "", "This field may not be blank"),
    ])
    def test_validation_errors(self, admin_client, field, value, error):
        """Returns validation errors for invalid data."""
        payload = {"email": "test@example.com", "name": "Test"}
        payload[field] = value

        response = admin_client.post(self.endpoint, payload, format="json")

        assert response.status_code == status.HTTP_400_BAD_REQUEST
        assert error in str(response.data[field])


@pytest.mark.django_db
class TestUserCreateAPIRefactor:
    """Refactored from repetitive tests using parametrize."""

    endpoint = "/api/v1/users/"

    # Before parametrize — repeated structure:
    # def test_validate_email_invalid(self, admin_client): ...
    # def test_validate_email_empty(self, admin_client): ...
    # def test_validate_name_empty(self, admin_client): ...

    # After parametrize — one function, data table:
    @pytest.mark.parametrize("field,value,error", [
        ("email", "not-an-email", "Enter a valid email address"),
        ("email", "", "This field may not be blank"),
        ("name", "", "This field may not be blank"),
        ("user_type", "unknown", "is not a valid choice"),
    ])
    def test_invalid_field_returns_400(self, admin_client, field, value, error):
        payload = {"email": "ok@example.com", "name": "OK", "user_type": "regular"}
        payload[field] = value

        response = admin_client.post(self.endpoint, payload, format="json")

        assert response.status_code == status.HTTP_400_BAD_REQUEST
        assert error in str(response.data)

# Before: 5 repetitive functions
def test_validate_email_valid(self):
    assert validate_email("user@example.com") == True

def test_validate_email_valid_subdomain(self):
    assert validate_email("user@mail.example.com") == True

def test_validate_email_invalid_no_at(self):
    assert validate_email("userexample.com") == False

def test_validate_email_invalid_no_domain(self):
    assert validate_email("user@") == False

def test_validate_email_invalid_empty(self):
    assert validate_email("") == False


# After: one function, 5 cases
@pytest.mark.parametrize("email,expected", [
    ("user@example.com", True),
    ("user@mail.example.com", True),
    ("userexample.com", False),    # No @ symbol
    ("user@", False),              # No domain
    ("", False),                   # Empty string
], ids=[
    "valid-simple",
    "valid-subdomain",
    "invalid-no-at",
    "invalid-no-domain",
    "invalid-empty",
])
def test_email_validation(self, email, expected):
    """Email validation covers all edge cases."""
    assert validate_email(email) == expected

import pytest
from rest_framework import status


@pytest.mark.django_db
class TestOrderAPIPermissions:
    """Permission matrix for Order API endpoints."""

    @pytest.mark.parametrize("fixture_name,expected_status", [
        ("api_client", status.HTTP_401_UNAUTHORIZED),
        ("authenticated_client", status.HTTP_200_OK),
        ("admin_client", status.HTTP_200_OK),
    ])
    def test_list_orders_permissions(self, request, fixture_name, expected_status):
        """Each role sees the correct status on GET /orders/."""
        client = request.getfixturevalue(fixture_name)
        response = client.get("/api/v1/orders/")
        assert response.status_code == expected_status

    @pytest.mark.parametrize("fixture_name,expected_status", [
        ("api_client", status.HTTP_401_UNAUTHORIZED),
        ("authenticated_client", status.HTTP_403_FORBIDDEN),
        ("admin_client", status.HTTP_201_CREATED),
    ])
    def test_create_order_permissions(self, request, fixture_name, expected_status):
        """Only admins can create orders directly."""
        client = request.getfixturevalue(fixture_name)
        payload = {"description": "Test Order"}
        response = client.post("/api/v1/orders/", payload, format="json")
        assert response.status_code == expected_status

@pytest.mark.django_db
class TestOrderReadPermissions:
    """Read permission matrix using getfixturevalue."""

    @pytest.mark.parametrize("client_fixture,expected", [
        ("api_client", 401),
        ("authenticated_client", 200),
        ("admin_client", 200),
    ])
    def test_read_endpoint(self, request, order, client_fixture, expected):
        """GET /orders/{uid}/ returns correct status per role."""
        client = request.getfixturevalue(client_fixture)
        response = client.get(f"/api/v1/orders/{order.uid}/")
        assert response.status_code == expected
